18	func main() {
19		if err := run(context.Background(), os.Args[1:]); err != nil {
20			fmt.Fprintf(os.Stderr, "error: %v\n", err)
21			os.Exit(1)
22		}
23	}
24	
25	func run(ctx context.Context, args []string) error {
26		if len(args) == 0 {
27			return usageError("")
28		}
29	
30		switch args[0] {
31		case "sync":
32			return runSyncLike(ctx, "sync", args[1:], false, gitsync.ModeSync)
33		case "replicate":
34			return runSyncLike(ctx, "replicate", args[1:], false, gitsync.ModeReplicate)
35		case "plan":
36			return runSyncLike(ctx, "plan", args[1:], true, "")
37		case "bootstrap":
38			return runBootstrap(ctx, args[1:])
39		case "probe":
40			return runProbe(ctx, args[1:])
41		case "fetch":
42			return runFetch(ctx, args[1:])
43		case "help", "-h", "--help":
44			return usageError("")
45		default:
46			return usageError(fmt.Sprintf("unknown command %q", args[0]))
47		}
48	}
