50	func runSyncLike(ctx context.Context, name string, args []string, dryRun bool, defaultMode gitsync.OperationMode) error {
51		fs := flag.NewFlagSet(name, flag.ContinueOnError)
52		fs.SetOutput(os.Stderr)
53	
54		var mappings multiStringFlag
55		var jsonOutput bool
56		var sourceAuth gitsync.EndpointAuth
57		var targetAuth gitsync.EndpointAuth
58		req := unstable.SyncRequest{DryRun: dryRun}
59	
60		fs.StringVar(&req.Source.URL, "source-url", "", "source repository URL")
61		fs.StringVar(&req.Target.URL, "target-url", "", "target repository URL")
62		fs.BoolVar(&req.Source.FollowInfoRefsRedirect, "source-follow-info-refs-redirect", envBool("GITSYNC_SOURCE_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up source RPCs to the final /info/refs redirect host")
63		fs.BoolVar(&req.Target.FollowInfoRefsRedirect, "target-follow-info-refs-redirect", envBool("GITSYNC_TARGET_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up target RPCs to the final /info/refs redirect host")
64	
65		fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
66		fs.StringVar(&targetAuth.Token, "target-token", envOr("GITSYNC_TARGET_TOKEN", ""), "target token/password")
67		fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
68		fs.StringVar(&targetAuth.Username, "target-username", envOr("GITSYNC_TARGET_USERNAME", "git"), "target basic auth username")
69		fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
70		fs.BoolVar(&targetAuth.SkipTLSVerify, "target-insecure-skip-tls-verify", envBool("GITSYNC_TARGET_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the target")
71	
72		fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
73		fs.StringVar(&targetAuth.BearerToken, "target-bearer-token", envOr("GITSYNC_TARGET_BEARER_TOKEN", ""), "target bearer token")
74	
75		branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
76		fs.Var(&mappings, "map", "ref mapping in src:dst form; short names map branches, full refs map exact refs")
77		modeValue := operationModeFlag(defaultOperationMode(defaultMode))
78		if name == "plan" {
79			fs.Var(&modeValue, "mode", "operation mode: sync or replicate")
80		}
81		fs.BoolVar(&req.Policy.IncludeTags, "tags", false, "mirror tags")
82		fs.BoolVar(&req.Policy.Force, "force", false, "allow non-fast-forward branch updates and retarget tags")
83		fs.BoolVar(&req.Policy.Prune, "prune", false, "delete managed target refs that no longer exist on source")
84		fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
85		fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
86		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
87		fs.IntVar(&req.Options.MaterializedMaxObjects, "materialized-max-objects", unstable.DefaultMaterializedMaxObjects, "abort non-relay materialized syncs above this many objects")
88		fs.Int64Var(&req.Options.MaxPackBytes, "max-pack-bytes", 0, "abort bootstrap-relay push if the streamed source pack exceeds this many bytes")
89		fs.Int64Var(&req.Options.TargetMaxPackBytes, "target-max-pack-bytes", 0, "target receive-pack body size limit; batches are planned and auto-subdivided to fit")
90		protocolValue := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
91		fs.Var(&protocolValue, "protocol", "protocol mode: auto, v1, or v2")
92		fs.BoolVar(&req.Options.Verbose, "v", false, "verbose logging")
93	
94		if err := fs.Parse(args); err != nil {
95			return fmt.Errorf("parse flags: %w", err)
96		}
97		req.Policy.Mode = gitsync.OperationMode(modeValue)
98		req.Policy.Protocol = gitsync.ProtocolMode(protocolValue)
99	
100		positional := fs.Args()
101		if req.Source.URL == "" && len(positional) > 0 {
102			req.Source.URL = positional[0]
103		}
104		if req.Target.URL == "" && len(positional) > 1 {
105			req.Target.URL = positional[1]
106		}
107		if len(positional) > 2 {
108			return usageError("too many positional arguments")
109		}
110	
111		if *branches != "" {
112			req.Scope.Branches = splitCSV(*branches)
113		}
114		for _, raw := range mappings {
115			mapping, err := validation.ParseMapping(raw)
116			if err != nil {
117				return fmt.Errorf("parse mapping %q: %w", raw, err)
118			}
119			req.Scope.Mappings = append(req.Scope.Mappings, gitsync.RefMapping{
120				Source: mapping.Source,
121				Target: mapping.Target,
122			})
123		}
124	
125		if req.Source.URL == "" || req.Target.URL == "" {
126			return usageError(name + " requires source and target repository URLs")
127		}
128	
129		client := unstable.New(unstable.Options{
130			Auth: gitsync.StaticAuthProvider{Source: sourceAuth, Target: targetAuth},
131		})
132		var (
133			result unstable.Result
134			err    error
135		)
136		if dryRun {
137			result, err = client.Plan(ctx, req)
138		} else {
139			if req.Policy.Mode == gitsync.ModeReplicate {
140				result, err = client.Replicate(ctx, req)
141			} else {
142				result, err = client.Sync(ctx, req)
143			}
144		}
145		if err != nil {
146			return fmt.Errorf("sync: %w", err)
147		}
148		printOutput(jsonOutput, result)
149	
150		if !dryRun && result.Blocked > 0 {
151			return errors.New("one or more branches were skipped because the target was not fast-forwardable")
152		}
153		return nil
154	}
