265		if err := fs.Parse(args); err != nil {
266			return fmt.Errorf("parse flags: %w", err)
267		}
268		req.Protocol = gitsync.ProtocolMode(probeProtocol)
269	
270		positional := fs.Args()
271		if req.Source.URL == "" && len(positional) > 0 {
272			req.Source.URL = positional[0]
