390	type multiStringFlag []string
391	
392	func (m *multiStringFlag) String() string {
393		return strings.Join(*m, ",")
394	}
395	
396	func (m *multiStringFlag) Set(value string) error {
397		*m = append(*m, value)
398		return nil
399	}
400	
401	func splitCSV(value string) []string {
402		parts := strings.Split(value, ",")
403		out := make([]string, 0, len(parts))
404		for _, part := range parts {
405			part = strings.TrimSpace(part)
406			if part != "" {
407				out = append(out, part)
408			}
409		}
410		return out
411	}
412	
413	func envOr(key, fallback string) string {
414		value := os.Getenv(key)
415		if value == "" {
416			return fallback
417		}
418		return value
419	}
420	
421	func envBool(key string) bool {
422		value := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
423		return value == "1" || value == "true" || value == "yes" || value == "on"
424	}
