111	func (c *Client) buildSyncConfig(ctx context.Context, source Endpoint, target Endpoint, scope RefScope, policy SyncPolicy, collectStats, dryRun bool) (internalbridge.Config, error) {
112		sourceAuth, err := c.authFor(ctx, source, SourceRole)
113		if err != nil {
114			return internalbridge.Config{}, err
115		}
116		targetAuth, err := c.authFor(ctx, target, TargetRole)
117		if err != nil {
118			return internalbridge.Config{}, err
119		}
120		return internalbridge.SyncConfig(
121			bridgeEndpoint(source),
122			bridgeEndpointAuth(sourceAuth),
123			bridgeEndpoint(target),
124			bridgeEndpointAuth(targetAuth),
125			bridgeScope(scope),
126			bridgePolicy(policy),
127			collectStats,
128			dryRun,
129			c.httpClient,
130		), nil
131	}
