144	func (r SyncRequest) Validate() error {
145		if r.Source.URL == "" {
146			return errors.New("source URL is required")
147		}
148		if r.Target.URL == "" {
149			return errors.New("target URL is required")
150		}
151		if err := validateOperationMode(r.Policy.Mode); err != nil {
152			return err
153		}
154		if _, err := validation.NormalizeProtocolMode(string(r.Policy.Protocol)); err != nil {
155			return fmt.Errorf("normalize protocol: %w", err)
156		}
157		if _, err := validation.ValidateMappings(validationMappings(r.Scope.Mappings)); err != nil {
158			return fmt.Errorf("validate mappings: %w", err)
159		}
160		return nil
161	}
162	
163	func (r PlanRequest) Validate() error {
164		if r.Source.URL == "" {
165			return errors.New("source URL is required")
166		}
167		if r.Target.URL == "" {
168			return errors.New("target URL is required")
169		}
170		if err := validateOperationMode(r.Policy.Mode); err != nil {
171			return err
172		}
173		if _, err := validation.NormalizeProtocolMode(string(r.Policy.Protocol)); err != nil {
174			return fmt.Errorf("normalize protocol: %w", err)
175		}
176		if _, err := validation.ValidateMappings(validationMappings(r.Scope.Mappings)); err != nil {
177			return fmt.Errorf("validate mappings: %w", err)
178		}
179		return nil
180	}
181	
182	func (r ProbeRequest) Validate() error {
183		if r.Source.URL == "" {
184			return errors.New("source URL is required")
185		}
186		if r.Target != nil && r.Target.URL == "" {
187			return errors.New("target URL is required when target endpoint is provided")
188		}
189		if _, err := validation.NormalizeProtocolMode(string(r.Protocol)); err != nil {
190			return fmt.Errorf("normalize protocol: %w", err)
191		}
192		return nil
193	}
