195	func bridgeEndpoint(ep Endpoint) internalbridge.Endpoint {
196		return internalbridge.Endpoint{
197			URL:                    ep.URL,
198			FollowInfoRefsRedirect: ep.FollowInfoRefsRedirect,
199		}
200	}
201	
202	func bridgeEndpointAuth(auth EndpointAuth) internalbridge.EndpointAuth {
203		return internalbridge.EndpointAuth{
204			Username:      auth.Username,
205			Token:         auth.Token,
206			BearerToken:   auth.BearerToken,
207			SkipTLSVerify: auth.SkipTLSVerify,
208		}
209	}
210	
211	func bridgeScope(scope RefScope) internalbridge.RefScope {
212		mappings := make([]internalbridge.RefMapping, 0, len(scope.Mappings))
213		for _, mapping := range scope.Mappings {
214			mappings = append(mappings, internalbridge.RefMapping{
215				Source: mapping.Source,
216				Target: mapping.Target,
217			})
218		}
219		return internalbridge.RefScope{
220			Branches: append([]string(nil), scope.Branches...),
221			Mappings: mappings,
222		}
223	}
224	
225	func bridgePolicy(policy SyncPolicy) internalbridge.SyncPolicy {
226		return internalbridge.SyncPolicy{
227			Mode:        internalbridge.OperationMode(policy.Mode),
228			IncludeTags: policy.IncludeTags,
229			Force:       policy.Force,
230			Prune:       policy.Prune,
231			Protocol:    internalbridge.ProtocolMode(policy.Protocol),
232		}
233	}
234	
235	func validateOperationMode(mode OperationMode) error {
236		switch mode {
237		case "", ModeSync, ModeReplicate:
238			return nil
239		default:
240			return fmt.Errorf("unsupported operation mode %q", mode)
241		}
242	}
243	
244	func ptr[T any](v T) *T {
245		return &v
246	}
247	
248	func validationMappings(mappings []RefMapping) []validation.RefMapping {
249		out := make([]validation.RefMapping, 0, len(mappings))
250		for _, mapping := range mappings {
251			out = append(out, validation.RefMapping{
252				Source: mapping.Source,
253				Target: mapping.Target,
254			})
255		}
256		return out
257	}
