12	
13	// PacketType represents the type of a pkt-line packet.
14	type PacketType int
15	
16	const (
17		PacketData        PacketType = iota
18		PacketFlush                  // 0000
19		PacketDelim                  // 0001
20		PacketResponseEnd            // 0002
21	)
22	
23	// PacketReader reads pkt-line formatted data. It reuses a fixed header buffer
24	// and a growable payload buffer to reduce allocations (issue #17).
25	type PacketReader struct {
26		r      *bufio.Reader
27		header [4]byte
28		buf    []byte
29	}
30	
31	func NewPacketReader(r io.Reader) *PacketReader {
32		if br, ok := r.(*bufio.Reader); ok {
33			return &PacketReader{r: br, buf: make([]byte, 0, 1024)}
34		}
35		return &PacketReader{r: bufio.NewReaderSize(r, 65536), buf: make([]byte, 0, 1024)}
36	}
37	
38	// BufReader returns the underlying buffered reader for direct access
39	// (needed by sideband demuxer after switching to pack stream).
40	func (pr *PacketReader) BufReader() *bufio.Reader {
41		return pr.r
42	}
43	
44	// ReadPacket reads the next pkt-line packet. The returned payload slice is
45	// only valid until the next call to ReadPacket.
46	func (pr *PacketReader) ReadPacket() (PacketType, []byte, error) {
47		if _, err := io.ReadFull(pr.r, pr.header[:]); err != nil {
48			return PacketData, nil, fmt.Errorf("read pktline header: %w", err)
49		}
50	
51		switch string(pr.header[:]) {
52		case "0000":
53			return PacketFlush, nil, nil
54		case "0001":
55			return PacketDelim, nil, nil
56		case "0002":
57			return PacketResponseEnd, nil, nil
58		}
59	
60		n, err := parseHexLength(pr.header)
61		if err != nil {
62			return PacketData, nil, err
63		}
64		if n <= 4 {
65			return PacketData, nil, pktline.ErrInvalidPktLen
66		}
67	
68		payloadLen := n - 4
69		if payloadLen > cap(pr.buf) {
70			pr.buf = make([]byte, payloadLen)
71		} else {
72			pr.buf = pr.buf[:payloadLen]
73		}
74		if _, err := io.ReadFull(pr.r, pr.buf); err != nil {
75			return PacketData, nil, fmt.Errorf("read pktline payload: %w", err)
76		}
77		return PacketData, pr.buf, nil
78	}
79	
80	func parseHexLength(header [4]byte) (int, error) {
81		var n int
82		for _, b := range header {
83			v, ok := hexVal(b)
84			if !ok {
85				return 0, pktline.ErrInvalidPktLen
86			}
87			n = 16*n + int(v)
88		}
89		return n, nil
90	}
91	
92	func hexVal(b byte) (byte, bool) {
93		switch {
94		case b >= '0' && b <= '9':
95			return b - '0', true
96		case b >= 'a' && b <= 'f':
97			return b - 'a' + 10, true
98		case b >= 'A' && b <= 'F':
99			return b - 'A' + 10, true
100		default:
101			return 0, false
102		}
103	}
104	
105	// EncodeCommand builds a pkt-line encoded v2 command request.
106	func EncodeCommand(command string, capArgs, cmdArgs []string) ([]byte, error) {
107		var buf bytes.Buffer
108		if _, err := pktline.Writef(&buf, "command=%s\n", command); err != nil {
109			return nil, fmt.Errorf("write command: %w", err)
110		}
111		for _, arg := range capArgs {
112			if _, err := pktline.Writef(&buf, "%s\n", arg); err != nil {
113				return nil, fmt.Errorf("write capability arg: %w", err)
114			}
115		}
116		if len(cmdArgs) > 0 {
117			if err := pktline.WriteDelim(&buf); err != nil {
118				return nil, fmt.Errorf("write delimiter: %w", err)
119			}
120			for _, arg := range cmdArgs {
121				if _, err := pktline.Writef(&buf, "%s\n", arg); err != nil {
122					return nil, fmt.Errorf("write command arg: %w", err)
123				}
124			}
125		}
126		if err := pktline.WriteFlush(&buf); err != nil {
127			return nil, fmt.Errorf("write flush: %w", err)
128		}
129		return buf.Bytes(), nil
130	}
131	
132	// SkipSection reads and discards packets until a delimiter or flush is reached.
133	func SkipSection(pr *PacketReader) error {
134		for {
135			kind, _, err := pr.ReadPacket()
136			if err != nil {
137				return err
138			}
139			if kind == PacketDelim || kind == PacketFlush {
140				return nil
141			}
142		}
143	}
144	
145	// HashHex is a helper to encode a 20-byte hash as lowercase hex.
146	func HashHex(h [20]byte) string {
147		return hex.EncodeToString(h[:])
148	}
149	
150	// FormatPktLine encodes a single pkt-line from a string payload.
151	func FormatPktLine(s string) string {
152		n := len(s) + 4
153		return fmt.Sprintf("%04x%s", n, s)
154	}
