74	// DecodeV2Capabilities parses a protocol v2 capability advertisement from an
75	// info/refs response body.
76	func DecodeV2Capabilities(r io.Reader) (*V2Capabilities, error) {
77		reader := NewPacketReader(r)
78	
79		// Skip service line and find "version 2\n"
80		for {
81			kind, payload, err := reader.ReadPacket()
82			if err != nil {
83				return nil, err
84			}
85			if kind == PacketFlush {
86				continue
87			}
88			if kind != PacketData {
89				return nil, fmt.Errorf("unexpected packet type %v before protocol advertisement", kind)
90			}
91			if strings.HasPrefix(string(payload), "# service=") {
92				continue
93			}
94			if string(payload) != "version 2\n" {
95				return nil, fmt.Errorf("unexpected protocol advertisement %q", payload)
96			}
97			break
98		}
99	
100		caps := &V2Capabilities{Caps: make(map[string]string)}
101		for {
102			kind, payload, err := reader.ReadPacket()
103			if err != nil {
104				return nil, err
105			}
106			if kind == PacketFlush {
107				return caps, nil
108			}
109			if kind != PacketData {
110				return nil, fmt.Errorf("unexpected packet type %v in capability advertisement", kind)
111			}
112			line := strings.TrimSuffix(string(payload), "\n")
113			name, value, _ := strings.Cut(line, "=")
114			caps.Caps[name] = value
115		}
116	}
