118	// PreferredSideband returns the best sideband capability supported by the
119	// server. Prefers sideband-64k over sideband (issue #4: sideband preference
120	// was backwards in original code).
121	func PreferredSideband(caps *capability.List) capability.Capability {
122		if caps.Supports(capability.Sideband64k) {
123			return capability.Sideband64k
124		}
125		if caps.Supports(capability.Sideband) {
126			return capability.Sideband
127		}
128		return ""
129	}
